import React, { useEffect, useState } from "react";
import {
  Box, Card, CardContent, Typography, Button,
  Grid, Snackbar, Alert
} from "@mui/material";
import { useNavigate } from "react-router-dom";
import axios from "axios";
import { useAuth } from "../../contexts/AuthContext";
import { io } from "socket.io-client";
import {
  MapContainer, TileLayer, Marker, Popup, Polyline
} from "react-leaflet";
import L from "leaflet";
import "leaflet/dist/leaflet.css";

const socket = io("http://localhost:5000");

export default function RiderDashboard() {
  const [pendingRides, setPendingRides] = useState([]);
  const [snackbar, setSnackbar] = useState({ open: false, message: "", type: "success" });

  const { auth, logout } = useAuth();
  const navigate = useNavigate();

  // 🚖 Fetch pending rides
  const fetchPendingRides = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/rides/pending", {
        headers: { Authorization: `Bearer ${auth?.token}` },
      });
      setPendingRides(res.data.rides || []);
    } catch {
      setSnackbar({ open: true, message: "Failed to fetch pending rides", type: "error" });
    }
  };

  // ✅ Accept ride
  const acceptRide = async (id) => {
    try {
      await axios.post(`http://localhost:5000/api/rides/${id}/accept`, {}, {
        headers: { Authorization: `Bearer ${auth?.token}` },
      });
      fetchPendingRides();
      setSnackbar({ open: true, message: "Ride accepted", type: "success" });
    } catch {
      setSnackbar({ open: true, message: "Failed to accept ride", type: "error" });
    }
  };

  // ❌ Reject ride
  const rejectRide = async (id) => {
    try {
      await axios.post(`http://localhost:5000/api/rides/${id}/reject`, {}, {
        headers: { Authorization: `Bearer ${auth?.token}` },
      });
      fetchPendingRides();
      setSnackbar({ open: true, message: "Ride rejected", type: "info" });
    } catch {
      setSnackbar({ open: true, message: "Failed to reject ride", type: "error" });
    }
  };

  // 🎧 Listen for live ride requests via socket.io
  useEffect(() => {
    fetchPendingRides();

    socket.on("rideRequest", (ride) => {
      setPendingRides((prev) => [...prev, ride]);
    });

    socket.on("rideCancelled", (ride) => {
      setPendingRides((prev) => prev.filter((r) => r._id !== ride._id));
    });

    return () => {
      socket.off("rideRequest");
      socket.off("rideCancelled");
    };
  }, []);

  // 🗺️ Marker icons
  const pickupIcon = new L.Icon({
    iconUrl: "https://cdn-icons-png.flaticon.com/512/32/32339.png",
    iconSize: [25, 25],
  });
  const dropIcon = new L.Icon({
    iconUrl: "https://cdn-icons-png.flaticon.com/512/684/684908.png",
    iconSize: [35, 35],
  });

  return (
    <Box p={4}>
      <Typography variant="h4" gutterBottom>Rider Dashboard</Typography>

      {/* Map view */}
      <Box sx={{ height: "500px", mb: 3 }}>
        <MapContainer center={[17.385, 78.4867]} zoom={12} style={{ height: "100%", width: "100%" }}>
          <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />
          {pendingRides.map((ride) => (
            <>
              {ride.pickupCoords && (
                <Marker key={`${ride._id}-pickup`} position={[ride.pickupCoords.lat, ride.pickupCoords.lng]} icon={pickupIcon}>
                  <Popup>
                    <Typography variant="body2"><b>Pickup:</b> {ride.pickup}</Typography>
                    <Button size="small" color="success" onClick={() => acceptRide(ride._id)}>Accept</Button>
                    <Button size="small" color="error" onClick={() => rejectRide(ride._id)}>Reject</Button>
                  </Popup>
                </Marker>
              )}
              {ride.dropCoords && (
                <Marker key={`${ride._id}-drop`} position={[ride.dropCoords.lat, ride.dropCoords.lng]} icon={dropIcon}>
                  <Popup>
                    <Typography variant="body2"><b>Drop:</b> {ride.drop}</Typography>
                  </Popup>
                </Marker>
              )}
              {ride.pickupCoords && ride.dropCoords && (
                <Polyline
                  positions={[
                    [ride.pickupCoords.lat, ride.pickupCoords.lng],
                    [ride.dropCoords.lat, ride.dropCoords.lng],
                  ]}
                  pathOptions={{ color: "black", weight: 3 }}
                />
              )}
            </>
          ))}
        </MapContainer>
      </Box>

      {/* Ride list below */}
      <Typography variant="h5" gutterBottom>Pending Ride Requests</Typography>
      <Grid container spacing={2}>
        {pendingRides.length === 0 ? (
          <Typography>No rides</Typography>
        ) : (
          pendingRides.map((ride) => (
            <Grid item xs={12} md={6} key={ride._id}>
              <Card sx={{ borderRadius: 3, boxShadow: 2 }}>
                <CardContent>
                  <Typography>Pickup: {ride.pickup}</Typography>
                  <Typography>Drop: {ride.drop}</Typography>
                  <Typography>Status: {ride.status}</Typography>
                  <Box mt={2} display="flex" gap={2}>
                    <Button variant="contained" color="success" onClick={() => acceptRide(ride._id)}>Accept</Button>
                    <Button variant="contained" color="error" onClick={() => rejectRide(ride._id)}>Reject</Button>
                  </Box>
                </CardContent>
              </Card>
            </Grid>
          ))
        )}
      </Grid>

      {/* Snackbar */}
      <Snackbar
        open={snackbar.open}
        autoHideDuration={3000}
        onClose={() => setSnackbar({ ...snackbar, open: false })}
      >
        <Alert severity={snackbar.type}>{snackbar.message}</Alert>
      </Snackbar>
    </Box>
  );
}
